import{_ as e,c as s,o as i,ah as n}from"./chunks/framework.C-x9UAyH.js";const k=JSON.parse('{"title":"Comandos para el uso de Índices en Oracle","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"oracle/indices.md","filePath":"oracle/indices.md","lastUpdated":1738877951000}'),l={name:"oracle/indices.md"};function t(d,a,o,r,c,p){return i(),s("div",null,[...a[0]||(a[0]=[n(`<h1 id="comandos-para-el-uso-de-indices-en-oracle" tabindex="-1">Comandos para el uso de Índices en Oracle <a class="header-anchor" href="#comandos-para-el-uso-de-indices-en-oracle" aria-label="Permalink to &quot;Comandos para el uso de Índices en Oracle&quot;">​</a></h1><p>Los índices son estructuras de datos asociadas a las tablas que permiten <strong>acceder más rápidamente a las filas</strong> mediante el uso de claves.</p><p>Los índices <strong>mejoran el rendimiento</strong> de las consultas y ayudan a reducir el tiempo de ejecución de operaciones que involucran búsquedas o filtrado de datos.</p><p>El uso más común de índices es en sentencias SELECT, WHERE, ORDER BY, GROUP BY, y uniones (JOIN).</p><h2 id="crear-un-indice" tabindex="-1">Crear un índice <a class="header-anchor" href="#crear-un-indice" aria-label="Permalink to &quot;Crear un índice&quot;">​</a></h2><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">CREATE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> INDEX</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> idx_empleado_nombre</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">ON</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> empleados (nombre);</span></span></code></pre></div><h2 id="indice-unico" tabindex="-1">Índice único <a class="header-anchor" href="#indice-unico" aria-label="Permalink to &quot;Índice único&quot;">​</a></h2><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">CREATE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> UNIQUE INDEX</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> idx_empleado_email</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">ON</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> empleados (email);</span></span></code></pre></div><p>Este índice único se asegura de que no haya dos filas con el mismo valor en la columna email de la tabla empleados. Si intentas insertar un registro con un valor de email que ya existe en otra fila, la base de datos generará un error y no permitirá la inserción.</p><h2 id="indice-basado-en-funciones" tabindex="-1">Índice basado en funciones <a class="header-anchor" href="#indice-basado-en-funciones" aria-label="Permalink to &quot;Índice basado en funciones&quot;">​</a></h2><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">CREATE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> INDEX</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> idx_upper_nombre</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">ON</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> empleados (</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">UPPER</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(nombre));</span></span></code></pre></div><h2 id="eliminar-un-indice" tabindex="-1">Eliminar un índice <a class="header-anchor" href="#eliminar-un-indice" aria-label="Permalink to &quot;Eliminar un índice&quot;">​</a></h2><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">DROP</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> INDEX</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> idx_empleado_nombre;</span></span></code></pre></div><p>No se puede eliminar un índice si está asociado a una restricción UNIQUE o PRIMARY KEY. En ese caso, primero se debe eliminar la restricción.</p>`,14)])])}const u=e(l,[["render",t]]);export{k as __pageData,u as default};
